function calculateGeopoliticalEnergyRisk(inputs) {
    const {
        geopoliticalConflictRisk,
        productionConcentrationIndex,
        transitChokepointDependency,
        sanctionEffectivenessLikelihood,
        demandSupplyBalanceVolatility,
        politicalStabilityOfProducers,
        strategicReserveCapacityDays,
        renewableEnergyIntegration
    } = inputs;

    // Input validation and clamping
    const GCR = Math.max(0, Math.min(10, geopoliticalConflictRisk));
    const PCI = Math.max(0, Math.min(100, productionConcentrationIndex));
    const TCD = Math.max(0, Math.min(100, transitChokepointDependency));
    const SEL = Math.max(0, Math.min(10, sanctionEffectivenessLikelihood));
    const DSBV = Math.max(0, Math.min(100, demandSupplyBalanceVolatility));
    const PSP = Math.max(0, Math.min(10, politicalStabilityOfProducers));
    const SRCD = Math.max(0, Math.min(365, strategicReserveCapacityDays));
    const REI = Math.max(0, Math.min(100, renewableEnergyIntegration));

    // Weights for risk-contributing factors (sum to 1)
    const W_GCR = 0.25; // Geopolitical Conflict Risk
    const W_PCI = 0.15; // Production Concentration Index
    const W_TCD = 0.20; // Transit Chokepoint Dependency
    const W_SEL = 0.15; // Sanction Effectiveness Likelihood
    const W_DSBV = 0.10; // Demand-Supply Balance Volatility
    const W_PSP = 0.15; // Political Stability of Producers (inverted)

    // Normalize risk factors to a 0-1 scale, inverting PSP as lower stability means higher risk
    const normalizedGCR = GCR / 10;
    const normalizedPCI = PCI / 100;
    const normalizedTCD = TCD / 100;
    const normalizedSEL = SEL / 10;
    const normalizedDSBV = DSBV / 100;
    const normalizedPSP = (10 - PSP) / 10; // Inverted: 0 stability = 1.0 risk, 10 stability = 0.0 risk

    // Calculate the raw unmitigated risk score (0-1 scale)
    const rawRiskScore = 
        (normalizedGCR * W_GCR) +
        (normalizedPCI * W_PCI) +
        (normalizedTCD * W_TCD) +
        (normalizedSEL * W_SEL) +
        (normalizedDSBV * W_DSBV) +
        (normalizedPSP * W_PSP);

    // Mitigation factors (normalize to 0-1 scale)
    const normalizedSRCD = SRCD / 365; // Max 365 days covers 1 year, so 1.0 for full coverage
    const normalizedREI = REI / 100;

    // Weights for mitigation factors (sum to 1 for mitigation impact)
    const M_SRCD = 0.4; // Strategic Reserve Capacity
    const M_REI = 0.6;  // Renewable Energy Integration

    // Calculate the total mitigation effect (0-1 scale)
    const totalMitigationEffect = 
        (normalizedSRCD * M_SRCD) +
        (normalizedREI * M_REI);

    // The mitigation effect directly reduces the raw risk score. 
    // A higher mitigation effect means a greater reduction in risk.
    let finalRiskScore = rawRiskScore * (1 - totalMitigationEffect);

    // Ensure the final risk score is within [0, 1] before scaling
    finalRiskScore = Math.max(0, Math.min(1, finalRiskScore));

    // Scale the final risk score to a 0-100 index
    const riskIndexScore = finalRiskScore * 100;

    let riskCategory;
    if (riskIndexScore <= 25) {
        riskCategory = "Low";
    } else if (riskIndexScore <= 50) {
        riskCategory = "Moderate";
    } else if (riskIndexScore <= 75) {
        riskCategory = "High";
    } else {
        riskCategory = "Critical";
    }

    return {
        riskIndexScore: parseFloat(riskIndexScore.toFixed(2)),
        riskCategory: riskCategory
    };
}
